def operate_ball_valve(handle_position):
    """
    Simulates the open/close operation of a ball valve.
    Args:
        handle_position (str): 'open' or 'closed'
    Returns:
        str: Status of the valve and flow state
    """
    if handle_position.lower() == 'open':
        return {
            'status': 'open',
            'flow': 'fluid passing through',
            'handle_alignment': 'aligned with flow path'
        }
    elif handle_position.lower() == 'closed':
        return {
            'status': 'closed',
            'flow': 'no flow',
            'handle_alignment': 'perpendicular to flow path'
        }
    else:
        return 'Invalid input. Use "open" or "closed".'

# Example usage:
print(operate_ball_valve('open'))  # {'status': 'open', 'flow': 'fluid passing through', ...}
print(operate_ball_valve('closed'))  # {'status': 'closed', 'flow': 'no flow', ...}
